import ssl
import json
import time
import machine
from umqtt.simple import MQTTClient

# Configuration
BROKER_IP = "192.168.1.100"
BROKER_PORT = 8883
CLIENT_ID = "esp32_sensor_01"
TOPIC = b"sensors/temp"
PUBLISH_INTERVAL = 10

# MQTT credentials - store these securely, not hardcoded in production
# In production, use a config file on the filesystem or NVS storage
MQTT_USER = "sensor_device"
MQTT_PASSWORD = "change_this_strong_password"

# TLS/SSL configuration for secure MQTT
SSL_PARAMS = {
    "server_hostname": BROKER_IP,
}

# Path to CA certificate for broker verification
# Upload ca_cert.der to the ESP32 filesystem beforehand
CA_CERT_PATH = "/ca_cert.der"


def load_ca_cert():
    """Load CA certificate for TLS verification."""
    try:
        with open(CA_CERT_PATH, "rb") as f:
            ca_cert = f.read()
        SSL_PARAMS["cert"] = ca_cert
        print("CA certificate loaded successfully")
        return True
    except OSError:
        print("WARNING: CA certificate not found at", CA_CERT_PATH)
        print("TLS will proceed without CA verification - NOT recommended for production")
        return False


def read_temperature():
    """Read temperature from internal sensor or connected sensor."""
    # Using ESP32 internal temperature sensor
    # Replace with your actual sensor (e.g., DS18B20, DHT22, BME280)
    try:
        # For ADC-based temperature sensor (e.g., TMP36 on GPIO34)
        adc = machine.ADC(machine.Pin(34))
        adc.atten(machine.ADC.ATTN_11DB)
        adc.width(machine.ADC.WIDTH_12BIT)

        # Average multiple readings for stability
        readings = []
        for _ in range(10):
            readings.append(adc.read())
            time.sleep_ms(10)

        avg_raw = sum(readings) / len(readings)

        # Convert ADC reading to voltage (3.3V reference, 12-bit)
        voltage = (avg_raw / 4095.0) * 3.3

        # TMP36: temperature = (voltage - 0.5) * 100
        temperature = (voltage - 0.5) * 100.0

        return round(temperature, 2)
    except Exception as e:
        print("Sensor read error:", e)
        return None


def create_mqtt_client():
    """Create and configure a secure MQTT client."""
    load_ca_cert()

    client = MQTTClient(
        CLIENT_ID,
        BROKER_IP,
        port=BROKER_PORT,
        user=MQTT_USER,
        password=MQTT_PASSWORD,
        keepalive=60,
        ssl=True,
        ssl_params=SSL_PARAMS,
    )

    return client


def connect_mqtt(client, max_retries=5):
    """Connect to MQTT broker with retry logic."""
    retry_delay = 2

    for attempt in range(max_retries):
        try:
            client.connect()
            print("Connected to MQTT broker at", BROKER_IP, "on port", BROKER_PORT)
            print("Using TLS encrypted connection")
            return True
        except OSError as e:
            print("Connection attempt", attempt + 1, "failed:", e)
            if attempt < max_retries - 1:
                print("Retrying in", retry_delay, "seconds...")
                time.sleep(retry_delay)
                retry_delay = min(retry_delay * 2, 30)

    print("Failed to connect after", max_retries, "attempts")
    return False


def publish_temperature(client, temperature):
    """Publish temperature reading as JSON payload."""
    payload = json.dumps({
        "client_id": CLIENT_ID,
        "temperature_c": temperature,
        "timestamp": time.time(),
        "unit": "celsius",
    })

    client.publish(TOPIC, payload.encode(), qos=1)
    print("Published to", TOPIC.decode(), "->", payload)


def validate_temperature(temp):
    """Basic sanity check on temperature reading."""
    if temp is None:
        return False
    if temp < -40 or temp > 125:
        print("Temperature reading out of valid range:", temp)
        return False
    return True


def main():
    """Main loop: connect and publish sensor data."""
    print("ESP32 Secure MQTT Sensor Node Starting...")
    print("Client ID:", CLIENT_ID)

    client = create_mqtt_client()

    if not connect_mqtt(client):
        print("Unable to establish MQTT connection. Resetting in 30s...")
        time.sleep(30)
        machine.reset()

    consecutive_failures = 0
    max_consecutive_failures = 5

    try:
        while True:
            temperature = read_temperature()

            if validate_temperature(temperature):
                try:
                    publish_temperature(client, temperature)
                    consecutive_failures = 0
                except OSError as e:
                    print("Publish failed:", e)
                    consecutive_failures += 1

                    if consecutive_failures >= max_consecutive_failures:
                        print("Too many failures. Reconnecting...")
                        try:
                            client.disconnect()
                        except Exception:
                            pass

                        if not connect_mqtt(client):
                            print("Reconnection failed. Resetting...")
                            time.sleep(10)
                            machine.reset()

                        consecutive_failures = 0
            else:
                print("Skipping invalid temperature reading")

            # Use lightsleep for power efficiency
            machine.lightsleep(PUBLISH_INTERVAL * 1000)

    except KeyboardInterrupt:
        print("Shutting down...")
    finally:
        try:
            client.disconnect()
            print("Disconnected from MQTT broker")
        except Exception:
            pass


if __name__ == "__main__":
    main()